                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [CascadingParameter(Name = "CartId")]
    public string? CartId { get; set; }

    private readonly record struct Product(int Id, string Name, decimal Price);

    private static readonly Product[] _products =
    [
        new(1, "Wireless Mouse", 29.99m),
        new(2, "Mechanical Keyboard", 79.99m),
        new(3, "USB-C Hub", 49.99m),
        new(4, "Monitor Stand", 39.99m),
        new(5, "Webcam HD", 59.99m),
        new(6, "Desk Lamp", 24.99m),
    ];

    private void AddToCart(Product product)
    {
        CartService.AddItem(CartId ?? string.Empty, product.Id, product.Name, product.Price);
    }
}

@page "/cart"
@rendermode InteractiveServer
@using sv_3e74b1fc668d4fafb6c18ed1f6f978d0.Services
@inject CartService CartService
@implements IDisposable

<PageTitle>Cart</PageTitle>

<h1>Shopping Cart</h1>

@if (_items.Count == 0)
{
    <p class="text-muted mt-3">Your cart is empty.</p>
    <a href="products" class="btn btn-primary">Browse Products</a>
}
else
{
    <table class="table mt-3">
        <thead>
            <tr>
                <th>Product</th>
                <th>Price</th>
                <th>Quantity</th>
                <th>Subtotal</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Name</td>
                    <td>@item.Price.ToString("C")</td>
                    <td>@item.Quantity</td>
                    <td>@((item.Price * item.Quantity).ToString("C"))</td>
                    <td>
                        <button class="btn btn-outline-danger btn-sm"
                                @onclick="() => Remove(item.Id)">
                            Remove
                        </button>
                    </td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr>
                <th colspan="3" class="text-end">Total:</th>
                <th>@_items.Sum(i => i.Price * i.Quantity).ToString("C")</th>
                <th></th>
            </tr>
        </tfoot>
    </table>

    <button class="btn btn-outline-secondary" @onclick="ClearCart">Clear Cart</button>
}

