using System.Collections.Concurrent;

namespace sv_3e74b1fc668d4fafb6c18ed1f6f978d0.Services;

/// <summary>
/// Singleton service that stores cart state keyed by a per-user cart identifier.
/// Cross-circuit notification is achieved via the OnChange event.
/// </summary>
public class CartService
{
    private readonly ConcurrentDictionary<string, List<CartItem>> _carts = new();
    private readonly ConcurrentDictionary<string, object> _locks = new();

    /// <summary>Fires with the cart ID that changed.</summary>
    public event Action<string>? OnChange;

    public void AddItem(string cartId, int productId, string name, decimal price)
    {
        var lockObj = _locks.GetOrAdd(cartId, _ => new object());
        var items = _carts.GetOrAdd(cartId, _ => new List<CartItem>());

        lock (lockObj)
        {
            var existing = items.FirstOrDefault(i => i.Id == productId);
            if (existing is not null)
            {
                existing.Quantity++;
            }
            else
            {
                items.Add(new CartItem
                {
                    Id = productId,
                    Name = name,
                    Price = price,
                    Quantity = 1
                });
            }
        }

        NotifyChange(cartId);
    }

    public void RemoveItem(string cartId, int productId)
    {
        if (!_carts.TryGetValue(cartId, out var items)) return;

        var lockObj = _locks.GetOrAdd(cartId, _ => new object());

        lock (lockObj)
        {
            items.RemoveAll(i => i.Id == productId);
        }

        NotifyChange(cartId);
    }

    public void Clear(string cartId)
    {
        if (!_carts.TryGetValue(cartId, out var items)) return;

        var lockObj = _locks.GetOrAdd(cartId, _ => new object());

        lock (lockObj)
        {
            items.Clear();
        }

        NotifyChange(cartId);
    }

    public IReadOnlyList<CartItem> GetItems(string cartId)
    {
        if (!_carts.TryGetValue(cartId, out var items)) return [];

        var lockObj = _locks.GetOrAdd(cartId, _ => new object());

        lock (lockObj)
        {
            return items.Select(i => new CartItem
            {
                Id = i.Id,
                Name = i.Name,
                Price = i.Price,
                Quantity = i.Quantity
            }).ToList().AsReadOnly();
        }
    }

    public int GetItemCount(string cartId)
    {
        if (!_carts.TryGetValue(cartId, out var items)) return 0;

        var lockObj = _locks.GetOrAdd(cartId, _ => new object());

        lock (lockObj)
        {
            return items.Sum(i => i.Quantity);
        }
    }

    private void NotifyChange(string cartId)
    {
        OnChange?.Invoke(cartId);
    }
}

