                    <td>@((item.Price * item.Quantity).ToString("C"))</td>
                    <td>
                        <button class="btn btn-outline-danger btn-sm"
                                @onclick="() => Remove(item.Id)">
                            Remove
                        </button>
                    </td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr>
                <th colspan="3" class="text-end">Total:</th>
                <th>@_items.Sum(i => i.Price * i.Quantity).ToString("C")</th>
                <th></th>
            </tr>
        </tfoot>
    </table>

    <button class="btn btn-outline-secondary" @onclick="ClearCart">Clear Cart</button>
}

@code {
    [CascadingParameter(Name = "CartId")]
    public string? CartId { get; set; }

    private IReadOnlyList<CartItem> _items = [];

    protected override void OnInitialized()
    {
        _items = CartService.GetItems(CartId ?? string.Empty);
        CartService.OnChange += HandleCartChanged;
    }

    private void HandleCartChanged(string changedCartId)
    {
        if (changedCartId != CartId) return;

        _items = CartService.GetItems(CartId ?? string.Empty);
        InvokeAsync(StateHasChanged);
    }

    private void Remove(int productId)
    {
        CartService.RemoveItem(CartId ?? string.Empty, productId);
    }

    private void ClearCart()
    {
        CartService.Clear(CartId ?? string.Empty);
    }

    public void Dispose()
    {
        CartService.OnChange -= HandleCartChanged;
    }
}

